import CollapsedText from '../components/CollapsedText';
import Button from '../components/Button';
import "../styles/Home.css";


function Home() {

  return <div className='home-app'>

    <CollapsedText
      title={"Game"}
      description={"First game"}
      content=
      {
        <Button
          buttonLabel="game"
          onClickNavigate="/game"
        />
      }
    />

  </div>
}

export default Home;
